import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useApp } from '../context/AppContext';
import { auth, orders } from '../api';
import {
  User, Mail, Shield, Calendar, Edit3, Save, X,
  Lock, Eye, EyeOff, Package, ShoppingBag, Settings
} from 'lucide-react';

const Profile = () => {
  const { user, setUser, t } = useApp();
  const navigate = useNavigate();

  const [isEditing, setIsEditing] = useState(false);
  const [showPasswordSection, setShowPasswordSection] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [ordersCount, setOrdersCount] = useState(0);
  const [showCurrentPass, setShowCurrentPass] = useState(false);
  const [showNewPass, setShowNewPass] = useState(false);
  const [showConfirmPass, setShowConfirmPass] = useState(false);

  const [form, setForm] = useState({
    username: user?.username || '',
    email: user?.email || '',
  });

  const [passForm, setPassForm] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });

  useEffect(() => {
    if (!user) { navigate('/login'); return; }
    setForm({ username: user.username, email: user.email });
    orders.getAll()
      .then(res => setOrdersCount(res.data.length))
      .catch(() => setOrdersCount(0));
  }, [user, navigate]);

  const handleSaveProfile = async (e) => {
    e.preventDefault();
    setMessage({ type: '', text: '' });
    try {
      const res = await auth.updateProfile({ username: form.username, email: form.email });
      setUser(res.data);
      setIsEditing(false);
      setMessage({ type: 'success', text: t.profileUpdated });
      setTimeout(() => setMessage({ type: '', text: '' }), 4000);
    } catch (err) {
      setMessage({ type: 'error', text: err.response?.data?.error || t.profileError });
    }
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    setMessage({ type: '', text: '' });
    if (passForm.newPassword !== passForm.confirmPassword) {
      setMessage({ type: 'error', text: t.passwordMismatch });
      return;
    }
    if (passForm.newPassword.length < 6) {
      setMessage({ type: 'error', text: '❌ Parol kamida 6 ta belgi bo\'lishi kerak' });
      return;
    }
    try {
      await auth.changePassword(passForm.currentPassword, passForm.newPassword);
      setPassForm({ currentPassword: '', newPassword: '', confirmPassword: '' });
      setShowPasswordSection(false);
      setMessage({ type: 'success', text: '✅ Parol muvaffaqiyatli o\'zgartirildi!' });
      setTimeout(() => setMessage({ type: '', text: '' }), 4000);
    } catch (err) {
      const errMsg = err.response?.data?.error === 'Current password is incorrect'
        ? '❌ Joriy parol noto\'g\'ri!'
        : (err.response?.data?.error || t.profileError);
      setMessage({ type: 'error', text: errMsg });
    }
  };

  if (!user) return null;

  const memberDate = user.created_at
    ? new Date(user.created_at).toLocaleDateString('uz-UZ', { year: 'numeric', month: 'long', day: 'numeric' })
    : '—';

  const avatarLetter = (user.username || 'U').charAt(0).toUpperCase();
  const avatarColors = ['#2563EB', '#7C3AED', '#DB2777', '#059669', '#D97706'];
  const avatarColor = avatarColors[user.id % avatarColors.length] || '#2563EB';

  return (
    <div className="container profile-page">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        {/* Header */}
        <div className="profile-header">
          <h1 className="section-title">{t.profileTitle}</h1>
          <Link to="/settings" className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Settings size={18} />
            {t.settings}
          </Link>
        </div>

        {/* Message */}
        {message.text && (
          <motion.div
            className={`message ${message.type}`}
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
          >
            {message.text}
          </motion.div>
        )}

        <div className="profile-grid">
          {/* Left: Avatar Card */}
          <motion.div
            className="profile-avatar-card"
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.1 }}
          >
            <div className="avatar-circle" style={{ background: avatarColor }}>
              {avatarLetter}
            </div>
            <h2 className="avatar-name">{user.username}</h2>
            <p className="avatar-email">{user.email}</p>
            <div className={`avatar-role ${user.role}`}>
              <Shield size={14} />
              {user.role === 'admin' ? t.admin : t.user}
            </div>

            <div className="profile-stats">
              <div className="profile-stat">
                <Package size={22} color="#2563EB" />
                <div>
                  <span className="stat-num">{ordersCount}</span>
                  <span className="stat-label">{t.ordersCount}</span>
                </div>
              </div>
              <div className="profile-stat">
                <ShoppingBag size={22} color="#F59E0B" />
                <div>
                  <span className="stat-num">0</span>
                  <span className="stat-label">{t.wishlistCount}</span>
                </div>
              </div>
            </div>

            <div className="profile-meta">
              <Calendar size={14} />
              <span>{t.memberSince}: {memberDate}</span>
            </div>
          </motion.div>

          {/* Right: Info & Edit */}
          <motion.div
            className="profile-info-card"
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.2 }}
          >
            {/* Profile Info */}
            <div className="profile-section">
              <div className="profile-section-header">
                <h3><User size={20} /> {t.editProfile}</h3>
                {!isEditing ? (
                  <button className="btn btn-secondary" onClick={() => setIsEditing(true)}>
                    <Edit3 size={16} /> {t.editProfile}
                  </button>
                ) : null}
              </div>

              {!isEditing ? (
                <div className="profile-fields-view">
                  <div className="profile-field">
                    <label><User size={14} /> {t.username}</label>
                    <span>{user.username}</span>
                  </div>
                  <div className="profile-field">
                    <label><Mail size={14} /> {t.email}</label>
                    <span>{user.email}</span>
                  </div>
                  <div className="profile-field">
                    <label><Shield size={14} /> {t.role}</label>
                    <span className={`role-badge ${user.role}`}>
                      {user.role === 'admin' ? t.admin : t.user}
                    </span>
                  </div>
                </div>
              ) : (
                <form onSubmit={handleSaveProfile} className="profile-edit-form">
                  <div className="form-group">
                    <label>{t.username}</label>
                    <input
                      type="text"
                      value={form.username}
                      onChange={e => setForm({ ...form, username: e.target.value })}
                      required
                      minLength={3}
                    />
                  </div>
                  <div className="form-group">
                    <label>{t.email}</label>
                    <input
                      type="email"
                      value={form.email}
                      onChange={e => setForm({ ...form, email: e.target.value })}
                      required
                    />
                  </div>
                  <div className="profile-edit-actions">
                    <motion.button
                      type="submit"
                      className="btn btn-primary"
                      whileTap={{ scale: 0.97 }}
                    >
                      <Save size={16} /> {t.saveChanges}
                    </motion.button>
                    <button
                      type="button"
                      className="btn btn-secondary"
                      onClick={() => { setIsEditing(false); setForm({ username: user.username, email: user.email }); }}
                    >
                      <X size={16} /> {t.cancel}
                    </button>
                  </div>
                </form>
              )}
            </div>

            {/* Password Section */}
            <div className="profile-section">
              <div className="profile-section-header">
                <h3><Lock size={20} /> {t.changePassword}</h3>
                {!showPasswordSection && (
                  <button className="btn btn-secondary" onClick={() => setShowPasswordSection(true)}>
                    <Lock size={16} /> {t.changePassword}
                  </button>
                )}
              </div>

              {showPasswordSection && (
                <motion.form
                  onSubmit={handleChangePassword}
                  className="profile-edit-form"
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                >
                  <div className="form-group">
                    <label>{t.currentPassword}</label>
                    <div className="password-input-wrap">
                      <input
                        type={showCurrentPass ? 'text' : 'password'}
                        value={passForm.currentPassword}
                        onChange={e => setPassForm({ ...passForm, currentPassword: e.target.value })}
                        required
                      />
                      <button type="button" className="pass-toggle" onClick={() => setShowCurrentPass(!showCurrentPass)}>
                        {showCurrentPass ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                  </div>
                  <div className="form-group">
                    <label>{t.newPassword}</label>
                    <div className="password-input-wrap">
                      <input
                        type={showNewPass ? 'text' : 'password'}
                        value={passForm.newPassword}
                        onChange={e => setPassForm({ ...passForm, newPassword: e.target.value })}
                        required
                        minLength={6}
                      />
                      <button type="button" className="pass-toggle" onClick={() => setShowNewPass(!showNewPass)}>
                        {showNewPass ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                  </div>
                  <div className="form-group">
                    <label>{t.confirmPassword}</label>
                    <div className="password-input-wrap">
                      <input
                        type={showConfirmPass ? 'text' : 'password'}
                        value={passForm.confirmPassword}
                        onChange={e => setPassForm({ ...passForm, confirmPassword: e.target.value })}
                        required
                        minLength={6}
                      />
                      <button type="button" className="pass-toggle" onClick={() => setShowConfirmPass(!showConfirmPass)}>
                        {showConfirmPass ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                  </div>
                  <div className="profile-edit-actions">
                    <motion.button
                      type="submit"
                      className="btn btn-primary"
                      whileTap={{ scale: 0.97 }}
                    >
                      <Save size={16} /> {t.saveChanges}
                    </motion.button>
                    <button
                      type="button"
                      className="btn btn-secondary"
                      onClick={() => { setShowPasswordSection(false); setPassForm({ currentPassword: '', newPassword: '', confirmPassword: '' }); }}
                    >
                      <X size={16} /> {t.cancel}
                    </button>
                  </div>
                </motion.form>
              )}
            </div>

            {/* Quick Links */}
            <div className="profile-section">
              <h3 style={{ marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                <Package size={20} /> Tezkor havolalar
              </h3>
              <div className="quick-links">
                <Link to="/orders" className="quick-link-btn">
                  <Package size={20} />
                  <span>{t.myOrders}</span>
                </Link>
                <Link to="/cart" className="quick-link-btn">
                  <ShoppingBag size={20} />
                  <span>{t.cart}</span>
                </Link>
                <Link to="/settings" className="quick-link-btn">
                  <Settings size={20} />
                  <span>{t.settings}</span>
                </Link>
              </div>
            </div>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
};

export default Profile;
